int tlLightAnimParamChannelChunk16::sortPriority = -1;

tlLightAnimParamChannelChunk16::tlLightAnimParamChannelChunk16()
{
    Init();
}

tlLightAnimParamChannelChunk16::tlLightAnimParamChannelChunk16(const tlLightAnimParamChannelChunk16& ch)
{
    Init();
    *this = ch;
}

tlLightAnimParamChannelChunk16::~tlLightAnimParamChannelChunk16()
{

}

tlLightAnimParamChannelChunk16::tlLightAnimParamChannelChunk16(tlReadChunk16* ch)
{
    assert(ch->GetID() == P3D_LIGHT_ANIM_PARAM_CHANNEL);
    ident = P3D_LIGHT_ANIM_PARAM_CHANNEL;

    tlFile* f = ch->GetFile();

    while (!ch->EndOfChunk())
    {
        AppendSubChunk(LoadSubChunk(f));
    }
    if(sortPriority == -1)
    {
        sortPriority = FindPriority(P3D_LIGHT_ANIM_PARAM_CHANNEL);
    }
}

void
tlLightAnimParamChannelChunk16::Init()
{
    ident = P3D_LIGHT_ANIM_PARAM_CHANNEL;
               
    if(sortPriority == -1)
    {
        sortPriority = FindPriority(P3D_LIGHT_ANIM_PARAM_CHANNEL);
    }
}

long 
tlLightAnimParamChannelChunk16::Size( )
{

    long s = 2*sizeof( long );

    int i;

    for( i=0; i < SubChunkCount( ); i++){
        s += GetSubChunk(i)->Size();
    }

    return s;
}

tlLightAnimParamChannelChunk16&
tlLightAnimParamChannelChunk16::operator=(const tlLightAnimParamChannelChunk16& a)
{

    if(ident != a.ident)
    {
        assert(ident != a.ident);
        return *this;
    }


    int subch;

    for(subch = 0; subch < subcount; subch++)
    {
        RemoveSubChunk(subch);
    }

    for(subch = 0; subch < a.subcount; subch++)
    {
        AppendSubChunk(a.GetSubChunk(subch)->Copy());
    }
    
    return *this;
}

bool
tlLightAnimParamChannelChunk16::operator==(const tlDataChunk& a)
{

    const tlLightAnimParamChannelChunk16* aptr = dynamic_cast<const tlLightAnimParamChannelChunk16*>(&a);

    if(aptr == NULL)
    {
        return false;
    }

    if(ident != aptr->ident)
    {
        return false;
    }



    // check the subchunks
    if(subcount != aptr->subcount)
    {
        return false;
    }

    for(int subch = 0; subch < subcount; subch++)
    {
        if(!((*GetSubChunk(subch)) == (*aptr->GetSubChunk(subch))))
        {
            return false;
        }
    }
    return true;
}

bool
tlLightAnimParamChannelChunk16::NameCompare(const tlDataChunk& a)
{

    // This chunk has no name, so we must compare the bits
    return operator==(a);
}


tlDataChunk*
tlLightAnimParamChannelChunk16::Create(tlReadChunk16* ch)
{
    tlDataChunk* dtCh = new tlLightAnimParamChannelChunk16(ch);
    return dtCh;
}

void
tlLightAnimParamChannelChunk16::Write(tlFile* f)
{
    tlWriteChunk16 ch(f, ident);


    ch.ContentFinish();
    for(int subch = 0; subch < subcount; subch++)
    {
        GetSubChunk(subch)->Write(f);
    }
}

void
tlLightAnimParamChannelChunk16::Print(int indent, unsigned int printdepth, unsigned int typemask)
{

    if ( printdepth == 0 )
    {
        return;
    }

    printf("%*stlLightAnimParamChannelChunk16 (%4x)\n",indent,"",(int) ident);

    if(subcount)
    {
        printf("%*s  SubChunks (%d):\n",indent,"",subcount);
        for(int subch = 0; subch < subcount; subch++)
        {
            GetSubChunk(subch)->Print(indent+4, printdepth-1, typemask);
        }
    }
}

void
tlLightAnimParamChannelChunk16::PrintFormatted(int indent)
{
    printf("%*schunk 0x%04x  \n",indent,"",(int) ident);
    if(subcount)
    {
        for(int i=0;i<subcount;i++)
        {
            GetSubChunk(i)->PrintFormatted(indent+2);
        }
    }
    printf("%*sendchunk\n",indent,"");
}

