tlDataChunk*
tlLightAnimParamChannelChunk16::Copy()
{
    return new tlLightAnimParamChannelChunk16(*this);
}

tlDataChunk*
tlLightAnimParamChannelChunk16::LoadSubChunk(tlFile* f)
{
    tlDataChunk *dch;
    tlReadChunk16  ch(f);
    ch.ReadNext();
    unsigned int id = ch.GetID();
 
    switch(id)
    {
    case P3D_CHANNEL_3DOF:
        dch = new tlChannel3DOFChunk16(&ch);
        break;
    default:
        dch = new tlDataChunk(id);
        int size = ch.GetDataSize();
        char* buf = new char[size];
        f->GetBytes(buf, size);
        dch->SetData(buf, size);
        delete buf;
    }
    ch.Skip();
    return dch;
}

